// Default values for a single anesthetic injection. Multiple injections live
// in fields.injections (array of these). Most procedures need only one; the
// "+ Add another anesthetic" button appends a new one.
const DEFAULT_INJECTION = {
  needle: "30G 25mm",                       // "30G 25mm" | "27G 35mm"
  drug: "lidocaine 1:100k epi",             // dropdown
  carpules: "1",                            // "1/4" | "1/2" | "1" | "2" | "3"
  side: "right",                            // "right" | "left"
  techIAN: false,                           // IAN + long buccal block
  techBuccalInfil: false,                   // Buccal infiltration #X
  techGreaterPalatine: false,               // Greater palatine block
  techNasopalatine: false,                  // Nasopalatine block
  techMaxInfil: false,                      // Maxillary buccal infiltration
};

// Returns an injection preset based on a single tooth number and patient type.
// Upper teeth and lower anteriors ‚Üí buccal infiltration.
// Lower posteriors (17-21 = LL, 28-32 = LR) ‚Üí IAN + long buccal, 27G 35mm.
// Peds always ‚Üí buccal infiltration (no block distinction for primary teeth).
const injectionForTooth = (tooth, isPeds) => {
  if (isPeds) return { ...DEFAULT_INJECTION, techBuccalInfil: true };
  const num = parseInt((tooth || "").replace(/\D/g, ""), 10);
  if (!num || num < 1 || num > 32) return null;
  const isRight = num <= 8 || num >= 25;
  const side = isRight ? "right" : "left";
  if ((num >= 17 && num <= 21) || (num >= 28 && num <= 32)) {
    return { ...DEFAULT_INJECTION, needle: "27G 35mm", side, techIAN: true };
  }
  return { ...DEFAULT_INJECTION, side, techBuccalInfil: true };
};

// Returns an injection preset for a given SRP quadrant (UR/UL/LR/LL).
// Upper quads ‚Üí maxillary buccal infiltration + greater palatine, 30G 25mm.
// Lower quads ‚Üí IAN + long buccal, 27G 35mm.
const injectionForQuad = (quad) => ({
  ...DEFAULT_INJECTION,
  needle: (quad === "LR" || quad === "LL") ? "27G 35mm" : "30G 25mm",
  side: (quad === "UR" || quad === "LR") ? "right" : "left",
  techIAN: quad === "LR" || quad === "LL",
  techMaxInfil: quad === "UR" || quad === "UL",
  techGreaterPalatine: quad === "UR" || quad === "UL",
});

