// SWADE_FREQ: count of how many times each code appears in the steps/template
// text ‚Äî used only as a sort weight so frequently-referenced codes (D0120,
// D1110, D4341‚Ä¶) rank first in "relevance" order. Not used for
// inclusion/exclusion ‚Äî SWADE_CODES is the authoritative source for that.
const SWADE_FREQ = (() => {
  const text = Object.values(TEMPLATES).join("\n") +
               "\n" + CHUNKS.map(c => c.body).join("\n");
  const matches = text.match(/D{1,2}\d{4}[A-Z]{0,2}(?:\.\d)?/g) || [];
  const freq = {};
  for (const m of matches) freq[m] = (freq[m] || 0) + 1;
  return freq;
})();

