  "D5120":  { desc: "Complete denture ‚Äî mandibular",                children: ["D5120A","D5120B","D5120C"] },
  "D9390":  { desc: "Consultation report",                          children: ["D9390A","D9390B"] },
  "D9630":  { desc: "Other drugs/medicaments",                      children: ["D9630.1","D9630.2","D9630.4"] },
  "D9940":  { desc: "Occlusal guard ‚Äî hard, full arch",             children: ["D9940A","D9940B"] },
  "D9944":  { desc: "Occlusal guard ‚Äî hard, partial arch",          children: ["D9944A","D9944B"] },
