// Reverse map: child code ‚Üí parent code (built from CODE_GROUPS).
const CHILD_TO_PARENT = {};
Object.entries(CODE_GROUPS).forEach(([p, g]) => g.children.forEach(c => { CHILD_TO_PARENT[c] = p; }));

// CDT category convention by code prefix. Used by the code lookup table
// for quick filtering.
const RVU_CATEGORIES = [
  { id: "all",   label: "All",            match: () => true },
  { id: "diag",  label: "Diagnostic",     match: c => /^D0/.test(c) },
  { id: "prev",  label: "Preventive",     match: c => /^D1/.test(c) },
  // Crowns (D27xx, prefab/SSC D292x‚ÄìD293x) are separated from fillings so
  // Restorative aligns with the MEE "Direct Restorative" category.
  { id: "rest",  label: "Restorative",    match: c => /^D2/.test(c) && !/^D27/.test(c) && !/^D29(2[0-9]|3[0-5])/.test(c) },
  { id: "endo",  label: "Endo",           match: c => /^D3/.test(c) },
  { id: "perio", label: "Perio",          match: c => /^D4/.test(c) },
  { id: "rpd",   label: "Removable",      match: c => /^D5/.test(c) },
  { id: "fix",   label: "Fixed/Implant",  match: c => /^D27/.test(c) || /^D29(2[0-9]|3[0-5])/.test(c) || /^D6/.test(c) },
  { id: "os",    label: "Oral Surgery",   match: c => /^D7/.test(c) },
  { id: "ortho", label: "Orthodontics",   match: c => /^D8/.test(c) },
  { id: "adj",   label: "Adjunctive",     match: c => /^D9/.test(c) },
  { id: "dig",   label: "Digital",        match: c => /^DD/.test(c) || /^RD/.test(c) },
  { id: "edu",   label: "IPE / Other",    match: c => /^I/.test(c) || /^R9/.test(c) || /^R5/.test(c) },
];

// MEE category structure mapping the UIC dashboard's 14 progress columns
// to D3/D4 thresholds and the CDT codes that count toward each category.
// Source: DAOB 333 Spring 2026 syllabus + UIC Student Dashboard reports.
//
// Each category has:
//   - dashKey: short label as it appears in the dashboard (used for the
//     input form so layout mirrors the dashboard order)
//   - d3 / d4: MEE threshold counts. A student is "at D3 level" when their
//     count >= d3, "at D4 level" when count >= d4. Below d3 is pink in the
//     dashboard, between d3 and d4 is yellow, at or above d4 is white.
//   - codeMatcher: returns true for any code that counts toward this
//     category. Used to surface "which procedures will close my gap?"
//   - notes: rendered as a small italic disclosure when the gap is shown,
//     for any UIC-specific rules (n=3 indirect rule, etc.)
const MEE_CATEGORIES = [
  {
    id: "diagnostic",
    dashKey: "Diagnostic",
    d3: 400, d4: 600,
    // Exams: D0120/D0140/D0147/D0150/D0160/D0170/D0180
    // Radiographs: D021x-D024x, D027x, D0330, D0340, D0350/D0351, D036x, D0372
    // Diagnostic tests: D0460, D0470, D0475, D0486; caries risk D0601-D0604
    codeMatcher: c =>
      /^D0(120|140|147|150|160|170|180)/.test(c) ||
      /^D02[1-4][0-9]/.test(c) ||
      /^D027[0-4]/.test(c) ||
      /^D0(330|340|350|351)/.test(c) ||
      /^D036[4-7]/.test(c) || /^D0372/.test(c) ||
      /^D0(460|470|475|486)/.test(c) ||
      /^D060[1-4]/.test(c),
  },
  {
    id: "prevention",
    dashKey: "Prevention",
    d3: 200, d4: 280,
    codeMatcher: c => /^D1(110|120|206|208|310|320|330|351|354)/.test(c),
  },
  {
    id: "directRest",
    dashKey: "Direct Rest",
    d3: 172, d4: 318,
    // Amalgam D2140-D2161, composite D2330-D2394, sedative fill D2940,
    // core buildup D2950, pin retention D2951
    codeMatcher: c =>
      /^D21[456]/.test(c) ||
      /^D23[3-9]/.test(c) ||
      /^D29(40|50|51)/.test(c),
  },
  {
    id: "indirectRestSU",
    dashKey: "InDirect Rest SU",
    d3: 30, d4: 200,
    // Inlays D2510-D2544, onlays D2610-D2664, crowns D2710-D2792,
    // other indirect D2980-D2983, all digital DD2xx codes
    codeMatcher: c =>
      /^D25[1-4][0-9]/.test(c) ||
      /^D26[1-6][0-9]/.test(c) ||
      /^D27[1-9][0-9]/.test(c) ||
      /^D298[0-3]/.test(c) ||
      /^DD2/.test(c),
    notes: "n=3 from DD codes or D2740. Class of 2026: at least 2 must be partial coverage (inlays/onlays).",
  },
  {
    id: "endo",
    dashKey: "Endo",
    d3: 12, d4: 35,
    // Pulp caps D3110/D3120, pulpotomy D3220/D3221, RCT D3310-D3330 (A/B),
    // retreatment D3346-D3348, apico D3410-D3426
    codeMatcher: c =>
      /^D31[012]0/.test(c) ||
      /^D322[01]/.test(c) ||
      /^D33[123]0[AB]?$/.test(c) ||
      /^D33(46|47|48)/.test(c) ||
      /^D34[12]/.test(c),
  },
  {
    id: "perio",
    dashKey: "Perio",
    d3: 220, d4: 380,
    // SRP D4341/D4342, perio maint D4346, full mouth debridement D4355, D4910
    codeMatcher: c => /^D4(341|342|346|355|910)/.test(c),
  },
  {
    id: "completeDent",
    dashKey: "Complete Dent",
    d3: 25, d4: 116,
    // Complete dentures D5110/D5120 (A/B/C), immediate D5130/D5140,
    // overdentures D5860/D5861, adjustments D5410/D5411, relines D5730/D5731/D5750/D5751/D5850/D5851
    codeMatcher: c =>
      /^D51[12]0[ABC]?$/.test(c) ||
      /^D51[34]/.test(c) ||
      /^D586[01]/.test(c) ||
      /^D5(41[01]|73[01]|75[01]|85[01])/.test(c),
  },
  {
    id: "partialDent",
    dashKey: "Partial Dent",
    d3: 5, d4: 70,
    // RPD D5211-D5214, D5221-D5224, interim D5820/D5821, RPD components D5611-D5660
    codeMatcher: c =>
      /^D52[12][1-4]/.test(c) ||
      /^D582[01]/.test(c) ||
      /^D56[1-6][0-9]/.test(c),
    notes: "n=1 mandatory: at least one D5213 or D5214 delivery to graduate.",
  },
  {
    id: "fdpImplants",
    dashKey: "FDP/Implants",
    d3: 5, d4: 30,
    // FPD pontics D6210-D6252, retainers D6710-D6792, implant codes
    // D6058-D6077, implant-supported D6114-D6117, DD digital codes
    codeMatcher: c =>
      /^D62[1-5]/.test(c) ||
      /^D67[1-9]/.test(c) ||
      /^D60(5[89]|6[0-9]|7[0-7])/.test(c) ||
      /^D611[4-7]/.test(c) ||
      /^DD60(58|65)/.test(c),
    notes: "n=1 mandatory: at least one implant-supported restoration.",
  },
  {
    id: "os",
    dashKey: "OS",
    d3: 155, d4: 170,
    // Simple extractions D7111/D7140, surgical D7210-D7250,
    // alveoloplasty D7310-D7321, root removal D7472/D7473, I&D D7510
    codeMatcher: c =>
      /^D71(11|40)/.test(c) ||
      /^D72[1-5]0/.test(c) ||
      /^D73[12][0-9]/.test(c) ||
      /^D7(472|473|510)/.test(c),
  },
  {
    id: "ortho",
    dashKey: "Ortho",
    d3: 10, d4: 10,
    // Comprehensive/limited D8010-D8099, space maintainers D1510/D1516/D1517,
    // retainers D8210, records/deband D8660/D8670/D8680, appliances D8703/D8704
    codeMatcher: c =>
      /^D80[1-9][0-9]/.test(c) ||
      /^D1(510|516|517)/.test(c) ||
      /^D8(210|660|670|680|703|704)/.test(c),
  },
  {
    id: "phase12",
    dashKey: "Phase I,II ReEval",
    d3: 5, d4: 10,
    // Comprehensive periodontal re-evaluation D0101/D0102
    codeMatcher: c => /^D010[12]/.test(c),
  },
  {
    id: "phase3",
    dashKey: "Phase III ReEval",
    d3: 10, d4: 30,
    codeMatcher: c => /^D0103/.test(c),
  },
  {
    id: "ga",
    dashKey: "GA",
    // No published threshold for GA ‚Äî included for completeness so the
    // student can see their count next to the others, but no gap math.
    d3: null, d4: null,
    codeMatcher: () => false,
  },
];

/* ============================================================================
 * MEE PROGRESS ‚Äî top of the RVUs tab.
 *
 * Designed to answer one question on first glance: "where am I, and what
 * do I need to do?" Layout:
 *
 *   - VERDICT (always visible if data entered): single sentence summary ‚Äî
 *     how many categories below D3, how many RVUs left to D4 across all.
 *
 *   - ACTION ITEMS: only categories where the student is below D4. Sorted
 *     biggest gap first. Each row shows current/D3/D4, gap, progress bar,
 *     and the top few high-RVU codes that count toward closing the gap.
 *
 *   - COMPLETED: categories already at D4 collapse to a single line.
 *
 *   - UPDATE FORM (collapsed by default): edit numbers, with +/- buttons
 *     for quick increment after a clinic session.
 * ==========================================================================*/

// Status of a count vs category thresholds.
function MEEProgress() {
  // Removed entirely ‚Äî the code lookup table is self-explanatory.
  return null;
}

function RVUs() {
  const [search, setSearch] = useState("");
  const [activeCategory, setActiveCategory] = useState("all");
  const [sortBy, setSortBy] = useState("relevance");
  const [sortDir, setSortDir] = useState("asc");
  // Hide codes that aren't referenced in the Swade manual. The full table is
  // exhaustive (every CDT code) and most students only ever use the subset
  // Swade documented; this toggle cuts noise without losing the option to
  // browse everything.
  const [swadeOnly, setSwadeOnly] = useState(true);
  const [showD3Pct, setShowD3Pct] = useState(false);
  const [showD4Pct, setShowD4Pct] = useState(false);
  const [expandedGroups, setExpandedGroups] = useState(new Set());
  const [showMeeMinPopup, setShowMeeMinPopup] = useState(false);

  // MEE = RVU total. Percentage = rvu / threshold √ó 100.
  const getMeePct = (code, rvu = 0) => {
    const cat = MEE_CATEGORIES.find(c => c.d3 !== null && c.codeMatcher(code));
    if (!cat || !rvu) return null;
    return {
      d3: cat.d3 ? (rvu * 100 / cat.d3) : null,
      d4: cat.d4 ? (rvu * 100 / cat.d4) : null,
      d3thresh: cat.d3,
      d4thresh: cat.d4,
      label: cat.dashKey,
    };
  };
  const showMee = showD3Pct || showD4Pct;
  const toggleGroup = code => setExpandedGroups(prev => {
    const s = new Set(prev); s.has(code) ? s.delete(code) : s.add(code); return s;
  });

  // Helper: is a code (or its parent group) SWADE-relevant?
  const isSwade = code => {
    if (SWADE_CODES.has(code)) return true;
    const grp = CODE_GROUPS[code];
    return grp ? grp.children.some(c => SWADE_CODES.has(c)) : false;
  };

  // Apply category filter + Swade filter + search filter, then sort.
  // Returns { rows, autoExpand } ‚Äî autoExpand is the set of parent codes whose
  // children matched the search term (so they open automatically).
  const { rows, autoExpand } = useMemo(() => {
    const q = search.trim().toLowerCase();
    const cat = RVU_CATEGORIES.find(c => c.id === activeCategory);

    // 1. Collect all candidate catalog entries after category filter.
    let base = RVU_DATA.filter(r => cat ? cat.match(r.code) : true);

    // 2. Determine which parent groups have at least one child in this category.
    const parentsInCat = new Set(
      base.filter(r => CHILD_TO_PARENT[r.code]).map(r => CHILD_TO_PARENT[r.code])
    );
    // Also include parent codes that are themselves in the catalog (e.g. D1320).
    base.filter(r => CODE_GROUPS[r.code]).forEach(r => parentsInCat.add(r.code));

    // 3. Build parent row objects for every qualifying parent.
    const parentEntries = [...parentsInCat].map(pCode => {
      const grp = CODE_GROUPS[pCode];
      const kids = grp.children.map(c => RVU_DATA.find(x => x.code === c)).filter(Boolean);
      return {
        _type: "parent", code: pCode, desc: grp.desc,
        rvu: kids.reduce((s, c) => s + (c.rvu || 0), 0),
        children: kids,
      };
    });

    // 4. Combine: standalone codes (not a child or a catalog-resident parent) + parent rows.
    let rows = [
      ...base
        .filter(r => !CHILD_TO_PARENT[r.code] && !CODE_GROUPS[r.code])
        .map(r => ({ _type: "single", ...r })),
      ...parentEntries,
    ];

    // 5. SWADE filter.
    if (swadeOnly) {
      rows = rows.filter(r =>
        r._type === "parent"
          ? r.children.some(c => SWADE_CODES.has(c.code)) || SWADE_CODES.has(r.code)
          : SWADE_CODES.has(r.code)
      );
    }

    // 6. Search filter ‚Äî also compute which parents to auto-expand.
    const autoExp = new Set();
    if (q) {
      rows = rows.filter(r => {
        if (r._type === "parent") {
          const parentMatch = r.code.toLowerCase().includes(q) || r.desc.toLowerCase().includes(q);
          const childMatch  = r.children.some(c =>
            c.code.toLowerCase().includes(q) || c.desc.toLowerCase().includes(q));
          if (childMatch) autoExp.add(r.code);
          return parentMatch || childMatch;
        }
        return r.code.toLowerCase().includes(q) || r.desc.toLowerCase().includes(q);
      });
    }

    // 7. Sort.
    rows.sort((a, b) => {
      let cmp = 0;
      if (sortBy === "relevance") {
        cmp = (isSwade(b.code) ? 1 : 0) - (isSwade(a.code) ? 1 : 0);
        if (cmp === 0) cmp = (SWADE_FREQ[b.code] || 0) - (SWADE_FREQ[a.code] || 0);
        if (cmp === 0) cmp = a.code.localeCompare(b.code);
      } else if (sortBy === "code") {
        cmp = a.code.localeCompare(b.code);
      } else if (sortBy === "desc") {
        cmp = a.desc.localeCompare(b.desc);
      } else if (sortBy === "rvu") {
        cmp = (a.rvu || 0) - (b.rvu || 0);
      }
      return sortDir === "asc" ? cmp : -cmp;
    });

    return { rows, autoExpand: autoExp };
  }, [search, sortBy, sortDir, activeCategory, swadeOnly]);

  // Per-category counts for the pill row (counts parent rows, not raw children).
  const categoryCounts = useMemo(() => {
    const counts = {};
    for (const cat of RVU_CATEGORIES) {
      let catBase = RVU_DATA.filter(r => cat.match(r.code));
      // Build parent rows for this category (same logic as main rows useMemo).
      const parentsHere = new Set([
        ...catBase.filter(r => CHILD_TO_PARENT[r.code]).map(r => CHILD_TO_PARENT[r.code]),
        ...catBase.filter(r => CODE_GROUPS[r.code]).map(r => r.code),
      ]);
      let visible = [
        ...catBase.filter(r => !CHILD_TO_PARENT[r.code] && !CODE_GROUPS[r.code]),
        ...[...parentsHere].map(p => ({ code: p, _parent: true })),
      ];
      if (swadeOnly) {
        visible = visible.filter(r =>
          r._parent
            ? CODE_GROUPS[r.code].children.some(c => SWADE_CODES.has(c)) || SWADE_CODES.has(r.code)
            : SWADE_CODES.has(r.code)
        );
      }
      counts[cat.id] = visible.length;
    }
    return counts;
  }, [swadeOnly]);

  // If the active category drops to zero codes (e.g. swadeOnly hides it), reset to "all".
  useEffect(() => {
    if (categoryCounts[activeCategory] === 0) setActiveCategory("all");
  }, [categoryCounts, activeCategory]);

  const toggleSort = (col) => {
    if (sortBy === col) {
      setSortDir(d => d === "asc" ? "desc" : "asc");
    } else {
      setSortBy(col);
      setSortDir(col === "rvu" ? "desc" : "asc");
    }
  };

  const sortIndicator = (col) =>
    sortBy === col ? (sortDir === "asc" ? "‚Üë" : "‚Üì") : "";

  const headerInput = {
    ...inputStyle,
    fontSize: "13px", padding: "8px 11px",
  };

  return (
    <div>
      {/* Primary: progress tracker */}
      <MEEProgress />

      {/* Code lookup table */}
      <div>
        {/* Search input */}
        <div style={{ marginBottom: "12px" }}>
          <label style={labelStyle}>Search code or description</label>
          <input type="text" value={search}
            onChange={e => setSearch(e.target.value)}
            placeholder="e.g. crown, D2740, prophy"
            style={headerInput} />
        </div>

        {/* Toggles row */}
        <div style={{ display: "flex", gap: "20px", flexWrap: "wrap", marginBottom: "16px" }}>
          {/* Swade-only toggle */}
          <label style={{
            display: "inline-flex", alignItems: "center", gap: "8px",
            fontSize: "11px", color: "var(--ink-soft)",
            cursor: "pointer",
            fontFamily: "'Geist', sans-serif",
            userSelect: "none",
          }}>
            <input type="checkbox" checked={swadeOnly}
              onChange={e => setSwadeOnly(e.target.checked)}
              style={{ accentColor: "var(--accent)", cursor: "pointer" }} />
            Hide codes not in <em className="serif" style={{ fontStyle: "italic" }}>(swade)</em> manual
          </label>
          {/* MEE contribution % toggles */}
          {[["D3", showD3Pct, setShowD3Pct], ["D4", showD4Pct, setShowD4Pct]].map(([lbl, val, set]) => (
            <label key={lbl} style={{
              display: "inline-flex", alignItems: "center", gap: "8px",
              fontSize: "11px", color: "var(--ink-soft)",
              cursor: "pointer",
              fontFamily: "'Geist', sans-serif",
              userSelect: "none",
            }}>
              <input type="checkbox" checked={val}
                onChange={e => set(e.target.checked)}
                style={{ accentColor: "var(--accent)", cursor: "pointer" }} />
              {lbl} MEE&nbsp;%
            </label>
          ))}

          {/* MEE Minimums popup ‚Äî pushed to far right */}
          <div style={{ marginLeft: "auto", position: "relative" }}>
            <button
              onClick={() => setShowMeeMinPopup(v => !v)}
              style={{
                background: "none", border: "none", padding: 0, cursor: "pointer",
                fontSize: "11px", color: "var(--accent)", fontFamily: "'Geist', sans-serif",
                textDecoration: "underline", textUnderlineOffset: "2px",
              }}
            >
              MEE Minimums
            </button>
            {showMeeMinPopup && (
              <>
                {/* backdrop to close on outside click */}
                <div
                  onClick={() => setShowMeeMinPopup(false)}
                  style={{
                    position: "fixed", inset: 0, zIndex: 49,
                  }}
                />
                <div style={{
                  position: "absolute", top: "calc(100% + 8px)", right: 0,
                  zIndex: 50, minWidth: "280px",
                  background: "var(--paper)", border: "1px solid var(--rule)",
                  borderRadius: "8px", boxShadow: "0 4px 20px rgba(0,0,0,0.12)",
                  padding: "14px 16px",
                  fontFamily: "'Geist', sans-serif",
                }}>
                  <div style={{
                    fontSize: "10px", letterSpacing: "0.16em", textTransform: "uppercase",
                    color: "var(--ink-faint)", fontWeight: 500, marginBottom: "10px",
                  }}>
                    MEE Minimums
                  </div>
                  <div style={{
                    display: "grid", gridTemplateColumns: "1fr 48px 48px",
                    gap: "4px 10px", alignItems: "baseline",
                    fontSize: "12px",
                  }}>
                    {/* header */}
                    <div style={{ fontSize: "10px", color: "var(--ink-faint)", letterSpacing: "0.1em", textTransform: "uppercase" }}>Category</div>
                    <div style={{ fontSize: "10px", color: "var(--ink-faint)", letterSpacing: "0.1em", textTransform: "uppercase", textAlign: "right" }}>D3</div>
                    <div style={{ fontSize: "10px", color: "var(--ink-faint)", letterSpacing: "0.1em", textTransform: "uppercase", textAlign: "right" }}>D4</div>
                    {/* rows */}
                    {MEE_CATEGORIES.map(cat => (
                      <Fragment key={cat.id}>
                        <div style={{ color: "var(--ink)", paddingTop: "3px", borderTop: "1px solid var(--rule-soft)" }}>{cat.dashKey}</div>
                        <div style={{ color: "var(--ink-soft)", textAlign: "right", paddingTop: "3px", borderTop: "1px solid var(--rule-soft)", fontVariantNumeric: "tabular-nums" }}>
                          {cat.d3 ?? "‚Äî"}
                        </div>
                        <div style={{ color: "var(--ink-soft)", textAlign: "right", paddingTop: "3px", borderTop: "1px solid var(--rule-soft)", fontVariantNumeric: "tabular-nums" }}>
                          {cat.d4 ?? "‚Äî"}
                        </div>
                      </Fragment>
                    ))}
                  </div>
                </div>
              </>
            )}
          </div>
        </div>

        {/* Category filter pills */}
        <div style={{
          display: "flex", flexWrap: "wrap", gap: "6px",
          marginBottom: "16px",
        }}>
          {RVU_CATEGORIES.map(cat => {
            const isActive = activeCategory === cat.id;
            const count = categoryCounts[cat.id];
            if (count === 0) return null;
            return (
              <button key={cat.id}
                onClick={() => setActiveCategory(cat.id)}
                style={{
                  fontSize: "11px",
                  padding: "5px 11px",
                  borderRadius: "999px",
                  fontFamily: "'Geist', sans-serif",
                  fontWeight: isActive ? 500 : 400,
                  cursor: "pointer",
                  border: `1px solid ${isActive ? "var(--accent)" : "var(--rule)"}`,
                  background: isActive ? "var(--accent)" : "var(--paper)",
                  color: isActive ? "var(--paper)" : "var(--ink-soft)",
                  letterSpacing: "0.02em",
                  transition: "all 140ms ease",
                }}>
                {cat.label}
                <span style={{
                  marginLeft: "6px", opacity: 0.7,
                  fontVariantNumeric: "tabular-nums",
                }}>{count}</span>
              </button>
            );
          })}
        </div>

        {/* Table ‚Äî fee col is fixed-width and sits left of Code so Code never shifts */}
        {(() => {
          const meeColW = showD3Pct && showD4Pct ? "80px" : "56px";
          // Column order: Description | Fee | Code | RVU | MEE Cat. | MEE %
          const cols = showMee ? `1fr 60px 80px 50px 140px ${meeColW}` : "1fr 60px 80px 50px";
          const meeHeader = showD3Pct && showD4Pct ? "D3 / D4" : showD3Pct ? "D3 %" : "D4 %";
          // Resolve MEE category label for a code (checks code itself then first child)
          const getMeeCat = (code, children = []) => {
            const check = c => MEE_CATEGORIES.find(m => m.codeMatcher(c))?.dashKey ?? null;
            return check(code) || children.map(c => check(c)).find(Boolean) || null;
          };
          const catCell = (label, small = false) => showMee ? (
            <div style={{
              fontSize: small ? "10px" : "11px",
              color: label ? "var(--ink-soft)" : "var(--ink-faint)",
              fontFamily: "'Geist', sans-serif",
              whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
            }}>
              {label || "‚Äî"}
            </div>
          ) : null;
          return (
        <div style={{ ...cardStyle, padding: 0, overflow: "hidden" }}>
          <div style={{
            display: "grid",
            gridTemplateColumns: cols,
            gap: "12px",
            fontSize: "10px", letterSpacing: "0.18em",
            textTransform: "uppercase", fontWeight: 500,
            color: "var(--ink-soft)",
            padding: "12px 18px", borderBottom: "1px solid var(--rule)",
            background: "var(--paper-soft)",
          }}>
            <button onClick={() => toggleSort("desc")} className="rvu-th"
              style={{ textAlign: "left" }}>
              Description {sortIndicator("desc")}
            </button>
            <div style={{ textAlign: "right", color: "var(--ink-soft)" }}>Fee</div>
            <button onClick={() => toggleSort("code")} className="rvu-th"
              style={{ textAlign: "center" }}>
              Code {sortIndicator("code")}
            </button>
            <button onClick={() => toggleSort("rvu")} className="rvu-th"
              style={{ textAlign: "right" }}>
              RVU {sortIndicator("rvu")}
            </button>
            {showMee && <div style={{ color: "var(--ink-soft)" }}>MEE cat.</div>}
            {showMee && (
              <div style={{ textAlign: "right", color: "var(--ink-soft)" }}>{meeHeader}</div>
            )}
          </div>

          <div style={{ maxHeight: "60vh", overflowY: "auto" }}>
            {rows.length === 0 ? (
              <div style={{ padding: "40px 20px", textAlign: "center",
                  color: "var(--ink-faint)", fontStyle: "italic" }}>
                No matches.
              </div>
            ) : rows.flatMap(r => {
              const isOpen = expandedGroups.has(r.code) || autoExpand.has(r.code);
              const rowSwade = isSwade(r.code);
              const fee = lookupFee(r.code);
              const rowStyle = {
                display: "grid", gridTemplateColumns: cols, gap: "12px",
                fontSize: "13px", lineHeight: 1.45, padding: "10px 18px",
                borderBottom: "1px solid var(--rule-soft)", alignItems: "center",
              };
              const codeCell = (code, swadeFlag) => (
                <div className="mono" style={{
                  color: "var(--accent)", fontWeight: 500,
                  fontVariantNumeric: "tabular-nums",
                  display: "flex", alignItems: "center", justifyContent: "center", gap: "4px",
                }}>
                  {swadeFlag && !swadeOnly && (
                    <span title="Used in the Swade guide" style={{
                      width: "5px", height: "5px", borderRadius: "50%",
                      background: "var(--accent)", display: "inline-block", flexShrink: 0,
                    }} />
                  )}
                  {code}
                </div>
              );

              const fmtPct = n => n == null || n === 0 ? null : (n < 1 ? n.toFixed(1) : n.toFixed(0)) + "%";
              // items = [{code, rvu}]. MEE % = rvu / threshold √ó 100.
              const meeCellContent = (items) => {
                const pcts = items.map(({ code, rvu }) => getMeePct(code, rvu)).filter(Boolean);
                if (!pcts.length) return <span style={{ color: "var(--ink-faint)" }}>‚Äî</span>;
                const sumD3 = pcts.reduce((a, p) => a + (p.d3 || 0), 0);
                const sumD4 = pcts.reduce((a, p) => a + (p.d4 || 0), 0);
                const d3thresh = pcts[0]?.d3thresh;
                const d4thresh = pcts[0]?.d4thresh;
                const tipParts = [];
                if (showD3Pct && d3thresh) tipParts.push(`D3 min: ${d3thresh} RVU`);
                if (showD4Pct && d4thresh) tipParts.push(`D4 min: ${d4thresh} RVU`);
                const tip = tipParts.join(" ¬∑ ") || undefined;
                if (showD3Pct && showD4Pct) {
                  return (
                    <div title={tip} style={{ display: "flex", flexDirection: "column", gap: "1px", alignItems: "flex-end" }}>
                      <span style={{ color: sumD3 ? "var(--teal)" : "var(--ink-faint)" }}>
                        {fmtPct(sumD3) || "‚Äî"}
                      </span>
                      <span style={{ color: sumD4 ? "var(--ink-soft)" : "var(--ink-faint)", fontSize: "11px" }}>
                        {fmtPct(sumD4) || "‚Äî"}
                      </span>
                    </div>
                  );
                }
                const val = fmtPct(showD3Pct ? sumD3 : sumD4);
                return val
                  ? <span title={tip}>{val}</span>
                  : <span style={{ color: "var(--ink-faint)" }}>‚Äî</span>;
              };
              const meeCell = (items, small = false) => showMee ? (
                <div style={{
                  textAlign: "right", fontVariantNumeric: "tabular-nums",
                  fontSize: small ? "11px" : "12px",
                  color: "var(--ink-soft)",
                }}>
                  {meeCellContent(items)}
                </div>
              ) : null;

              if (r._type === "parent") {
                const parentRow = (
                  <div key={r.code} style={rowStyle}>
                    <button onClick={() => toggleGroup(r.code)} style={{
                      background: "none", border: "none", padding: 0, cursor: "pointer",
                      color: "var(--ink)", textAlign: "left", fontFamily: "inherit",
                      fontSize: "inherit", display: "flex", alignItems: "center", gap: "6px",
                    }}>
                      <span style={{
                        fontSize: "10px", color: "var(--ink-soft)",
                        transition: "transform 120ms", display: "inline-block",
                        transform: isOpen ? "rotate(90deg)" : "rotate(0deg)",
                      }}>‚ñ∂</span>
                      {r.desc}
                    </button>
                    <div style={{
                      textAlign: "right",
                      color: fee ? "var(--ink-soft)" : "var(--ink-faint)",
                      fontVariantNumeric: "tabular-nums", fontSize: "12px",
                    }}>
                      {fee ? `$${fee}` : "‚Äî"}
                    </div>
                    {codeCell(r.code, rowSwade)}
                    <div style={{ textAlign: "right", color: "var(--ink-soft)",
                        fontVariantNumeric: "tabular-nums" }}>{r.rvu}</div>
                    {catCell(getMeeCat(r.code, r.children.map(c => c.code)))}
                    {meeCell(r.children.map(c => ({ code: c.code, rvu: c.rvu || 0 })))}
                  </div>
                );
                const childRows = isOpen ? r.children.map(child => (
                  <div key={child.code} style={{
                    ...rowStyle,
                    padding: "7px 18px 7px 36px",
                    background: "var(--paper-soft)",
                    borderBottom: "1px solid var(--rule-soft)",
                  }}>
                    <div style={{ color: "var(--ink-soft)", fontSize: "12px" }}>
                      {child.desc}
                    </div>
                    <div style={{
                      textAlign: "right", color: "var(--ink-faint)",
                      fontVariantNumeric: "tabular-nums", fontSize: "12px",
                    }}>‚Äî</div>
                    {codeCell(child.code, SWADE_CODES.has(child.code))}
                    <div style={{ textAlign: "right", color: "var(--ink-soft)",
                        fontVariantNumeric: "tabular-nums", fontSize: "12px" }}>{child.rvu}</div>
                    {catCell(getMeeCat(child.code), true)}
                    {meeCell([{ code: child.code, rvu: child.rvu || 0 }], true)}
                  </div>
                )) : [];
                return [parentRow, ...childRows];
              }

              // Single (non-grouped) row
              return [(
                <div key={r.code} style={rowStyle}>
                  <div style={{ color: "var(--ink)", textAlign: "left" }}>{r.desc}</div>
                  <div style={{
                    textAlign: "right",
                    color: fee ? "var(--ink-soft)" : "var(--ink-faint)",
                    fontVariantNumeric: "tabular-nums", fontSize: "12px",
                  }}>
                    {fee ? `$${fee}` : "‚Äî"}
                  </div>
                  {codeCell(r.code, rowSwade)}
                  <div style={{ textAlign: "right", color: "var(--ink-soft)",
                      fontVariantNumeric: "tabular-nums" }}>{r.rvu}</div>
                  {catCell(getMeeCat(r.code))}
                  {meeCell([{ code: r.code, rvu: r.rvu || 0 }])}
                </div>
              )];
            })}
          </div>
        </div>
          );
        })()}

        <p style={{
          marginTop: "14px", fontSize: "11px",
          color: "var(--ink-faint)", fontStyle: "italic",
          lineHeight: 1.5,
        }}>
          {!swadeOnly && (
            <>
              <span style={{
                width: "5px", height: "5px", borderRadius: "50%",
                background: "var(--accent)", display: "inline-block",
                marginRight: "6px", verticalAlign: "middle",
              }} />
              codes referenced in <em className="serif" style={{ fontStyle: "italic" }}>(swade)</em> manual
              {" ¬∑ "}
            </>
          )}
          fees from UIC predoctoral fee guide (Oct 2025)
        </p>
      </div>
    </div>
  );
}


/* ============================================================================
 * APP SHELL  ‚Äî  tabs, header, layout
 * ==========================================================================*/
/* ============================================================================
 * PE DATA ‚Äî 26 Performance Exams from UIC's Master Clinical PE Reference.
 *
 * Each PE has:
 *   id           ‚Äî short stable ID, used for navigation
 *   code         ‚Äî official UIC code (PER01, CR2, CRN1, etc.)
 *   name         ‚Äî human title
 *   part         ‚Äî which Part of the master doc it belongs to
 *   deadline     ‚Äî { semester: "D3-spring" | "D3-fall" | etc., text: human label }
 *                  Some PEs have "or earlier" / DAOB course attachments ‚Äî kept verbatim.
 *   prereq       ‚Äî human-readable prerequisite text
 *   prereqCheck  ‚Äî function (counts) ‚Üí { eligible: bool, gap?: { n, label } }
 *                  Returns null when the prereq doesn't map cleanly to MEE counts
 *                  (e.g. "after Caries Diagnosis PE" ‚Äî we don't track PE completion)
 *   caseSelect   ‚Äî case selection criteria
 *   protocol     ‚Äî protocol / instructions
 *   criteria     ‚Äî array of { name, excellent, acceptable, notMet } rubric rows
 *                  Some criteria have N/A in middle column ‚Äî represented as null
 *   criticalDeficiencies ‚Äî array of strings; each row is one deficiency
 *
 * Order in the SEMESTERS array drives the timeline layout.
 * ==========================================================================*/

const PE_SEMESTERS = [
  { id: "D3-summer", label: "D3 Summer", short: "Summer" },
  { id: "D3-fall",   label: "D3 Fall",   short: "Fall"   },
  { id: "D3-spring", label: "D3 Spring", short: "Spring" },
  { id: "D4-summer", label: "D4 Summer", short: "Summer" },
  { id: "D4-fall",   label: "D4 Fall",   short: "Fall"   },
  { id: "D4-spring", label: "D4 Spring", short: "Spring" },
];

const PE_PARTS = [
  { id: "perio",       label: "Periodontal Exams" },
  { id: "restFound",   label: "Restorative Foundation" },
  { id: "operative",   label: "Operative" },
  { id: "fixedProsth", label: "Fixed Prosthodontics" },
  { id: "removable",   label: "Removable Prosthodontics" },
  { id: "specialty",   label: "Specialty" },
  { id: "rotation",    label: "Rotation-Specific" },
];

// Prereq check helpers ‚Äî reach into MEE counts (which mirror the dashboard).
// Counts come from the same localStorage keys the RVU tab uses.
const checkCount = (counts, key, n, label) => {
  const cur = parseFloat(counts[key]) || 0;
  if (cur >= n) return { eligible: true };
  return { eligible: false, gap: { n: n - cur, label } };
};

